import type { Frame } from "./types.js";

export class ProtocolParseError extends Error {
  readonly code = "INVALID_FRAME" as const;
  constructor(message: string) {
    super(message);
    this.name = "ProtocolParseError";
  }
}

export function parse(raw: string): Frame {
  try {
    const obj = JSON.parse(raw);
    if (!obj || typeof obj !== "object") {
      throw new ProtocolParseError("Invalid JSON frame: not an object");
    }
    return obj as Frame;
  } catch (e) {
    if (e instanceof ProtocolParseError) throw e;
    throw new ProtocolParseError(`Failed to parse frame: ${(e as Error).message}`);
  }
}
